#!/usr/bin/env node
/**
 * Build src/data/kldb-occupation-mapping.json — a per-O*NET-code map to the
 * German KldB 2010 (Fassung 2020) occupation classification, providing both
 * an official German occupation name and a training-requirement category for
 * the Ausbildungs-Filter UI.
 *
 * Pipeline:
 *   1. Read scripts/input/kldb-data.json (1300 KldB-5d classes + DE names +
 *      1523 KldB-5d ↔ ISCO-4d crosswalk pairs with Schwerpunkt flag).
 *      Generated by extract-kldb.py from Bundesagentur xlsx sources.
 *   2. Reuse the ESCO infrastructure (tabiya-occupations.csv + ESCO↔O*NET
 *      crosswalk) from build-bigfive-profiles.mjs — chain is
 *      O*NET → ESCO → ISCO-4d, then ISCO-4d → KldB-5d candidates.
 *   3. For each O*NET code, pick ONE KldB candidate. Preference order:
 *        a. Schwerpunkt=true AND Anforderungsniveau matches jobZone target
 *        b. any AND Anforderungsniveau matches jobZone target
 *        c. Schwerpunkt=true AND closest Anforderungsniveau
 *        d. any AND closest Anforderungsniveau
 *      jobZone → preferred Anforderungsniveau (Anf) mapping:
 *        1 → 1, 2 → 2, 3 → 2, 4 → 3, 5 → 4, null → 2 (median)
 *   4. Emit per-O*NET: kldbCode, kldbName (DE), anforderungsniveau (1-4),
 *      trainingCategory ∈ {none | apprenticeship | specialist | studies}.
 *
 * Usage:
 *   node scripts/build-kldb-mapping.mjs
 */
import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs'
import { dirname, join } from 'node:path'
import { fileURLToPath } from 'node:url'
import { spawnSync } from 'node:child_process'
import { parse } from 'csv-parse/sync'

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT = join(__dirname, '..')

const KLDB_INPUT = join(ROOT, 'scripts/input/kldb-data.json')
const ONET_INPUT = join(ROOT, 'src/data/onet-occupations.json')
const ESCO_DIR = join(ROOT, 'data-raw/esco')
const CROSSWALK_PATH = join(ESCO_DIR, 'onet-esco-crosswalk.csv')
const CROSSWALK_URL =
  'https://esco.ec.europa.eu/system/files/2023-08/ONET_%28Occupations%29_0_updated.csv'
const TABIYA_PATH = join(ESCO_DIR, 'tabiya-occupations.csv')
const TABIYA_URL =
  'https://raw.githubusercontent.com/tabiya-tech/tabiya-open-dataset/main/tabiya-esco-v1.1.1/csv/occupations.csv'
const OUTPUT = join(ROOT, 'src/data/kldb-occupation-mapping.json')

const TRAINING_CATEGORY_BY_ANF = {
  1: 'none',
  2: 'apprenticeship',
  3: 'specialist',
  4: 'studies',
}

// O*NET jobZone → preferred KldB Anforderungsniveau (1..4). Fallback 2 if
// jobZone is missing — most O*NET occupations cluster at "Fachkraft" level.
const JOBZONE_TO_ANF = { 1: 1, 2: 2, 3: 2, 4: 3, 5: 4 }

function ensureDownload(path, url) {
  if (existsSync(path)) return
  mkdirSync(dirname(path), { recursive: true })
  console.log(`Downloading ${url} ...`)
  const res = spawnSync('curl', ['-sSL', '-o', path, url], { stdio: 'inherit' })
  if (res.status !== 0) throw new Error(`curl failed downloading ${url}`)
}

function loadKldb() {
  const raw = JSON.parse(readFileSync(KLDB_INPUT, 'utf-8'))
  const classByCode = new Map(raw.kldbClasses.map((c) => [c.code, c]))
  const kldbByIsco = new Map() // isco4d → [{kldb5d, schwerpunkt, ...class fields}]
  for (const pair of raw.kldbToIsco) {
    const cls = classByCode.get(pair.kldb5d)
    if (!cls) continue
    if (!kldbByIsco.has(pair.isco4d)) kldbByIsco.set(pair.isco4d, [])
    kldbByIsco.get(pair.isco4d).push({
      kldb5d: pair.kldb5d,
      schwerpunkt: pair.schwerpunkt,
      name: cls.name,
      anforderungsniveau: cls.anforderungsniveau,
    })
  }
  console.log(`KldB: ${classByCode.size} classes, ${kldbByIsco.size} ISCO-4d groups covered`)
  return { kldbByIsco, source: raw.source }
}

function loadEscoToIsco() {
  ensureDownload(TABIYA_PATH, TABIYA_URL)
  const csv = readFileSync(TABIYA_PATH, 'utf-8')
  const rows = parse(csv, { columns: true, skip_empty_lines: true })
  const byUri = new Map()
  for (const row of rows) {
    if (!row.ORIGINURI || !row.ISCOGROUPCODE) continue
    byUri.set(row.ORIGINURI.trim(), row.ISCOGROUPCODE.trim())
  }
  return byUri
}

function resolveIscoFromEscoUri(uri, escoToIsco) {
  const direct = uri.match(/\/esco\/isco\/C(\d{4})$/)
  if (direct) return direct[1]
  return escoToIsco.get(uri) ?? null
}

function loadCrosswalk() {
  ensureDownload(CROSSWALK_PATH, CROSSWALK_URL)
  const csv = readFileSync(CROSSWALK_PATH, 'utf-8')
  const rows = parse(csv, { columns: false, skip_empty_lines: true, relax_column_count: true })
  const pairs = []
  for (const row of rows) {
    if (row.length < 7) continue
    const onetCode = row[0]
    const escoUri = row[3]
    const matchType = (row[6] || '').trim()
    if (!/^\d{2}-\d{4}\.\d{2}$/.test(onetCode) || !escoUri) continue
    pairs.push({ onetCode, escoUri, matchType })
  }
  return pairs
}

// Higher = better. We prefer exactMatch, fall back through the chain.
const MATCH_TYPE_PRIORITY = { exactMatch: 4, closeMatch: 3, narrowMatch: 2, broadMatch: 1 }

function loadOnetMeta() {
  const occs = JSON.parse(readFileSync(ONET_INPUT, 'utf-8'))
  const byCode = new Map()
  for (const o of occs) {
    byCode.set(o.onetCode, {
      jobZone: o.jobZone ?? null,
      titleDe: o.title?.de ?? null,
      titleEn: o.title?.en ?? null,
    })
  }
  return byCode
}

// Token-set Jaccard-ish overlap over significant words (>=4 chars, lowercased,
// diacritics-stripped). Used only as a tiebreaker between KldB candidates that
// are otherwise equivalent (same Anf, same Schwerpunkt, same vote count).
function tokenize(s) {
  if (!s) return new Set()
  const normalized = s
    .toLowerCase()
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^\p{L}\s]/gu, ' ')
  return new Set(normalized.split(/\s+/).filter((w) => w.length >= 4))
}

// Shared-prefix stem match: treats "zimmerer" and "zimmerei" as the same
// concept via the 5-char stem "zimme". Cheap approximation of German noun
// stemming; robust enough to act as a tiebreaker without a full stemmer.
function stemsOverlap(titleA, titleB) {
  const stems = (set) => new Set([...set].map((t) => t.slice(0, 5)))
  const a = stems(tokenize(titleA))
  const b = stems(tokenize(titleB))
  if (a.size === 0 || b.size === 0) return 0
  let hits = 0
  for (const t of a) if (b.has(t)) hits++
  return hits / Math.min(a.size, b.size)
}

function scoreCandidate(candidate, preferredAnf, referenceTitle) {
  // Lower tuple wins. Order: anf-distance, schwerpunkt, -votes, -titleOverlap.
  return [
    Math.abs(candidate.anforderungsniveau - preferredAnf),
    candidate.schwerpunkt ? 0 : 1,
    -(candidate.votes ?? 1),
    -stemsOverlap(referenceTitle, candidate.name),
  ]
}

function compareScores(a, b) {
  for (let i = 0; i < a.length; i++) {
    if (a[i] !== b[i]) return a[i] - b[i]
  }
  return 0
}

function pickKldb(candidates, preferredAnf, referenceTitle) {
  let best = null
  let bestScore = null
  for (const c of candidates) {
    const score = scoreCandidate(c, preferredAnf, referenceTitle)
    if (!best || compareScores(score, bestScore) < 0) {
      best = c
      bestScore = score
    }
  }
  return best
}

function buildMappings(kldbByIsco, escoToIsco, crosswalk, onetMeta) {
  // Group crosswalk rows by O*NET code so we can filter by match-type tier.
  const byOnet = new Map() // onet → [{escoUri, matchType}]
  for (const entry of crosswalk) {
    if (!onetMeta.has(entry.onetCode)) continue
    if (!byOnet.has(entry.onetCode)) byOnet.set(entry.onetCode, [])
    byOnet.get(entry.onetCode).push(entry)
  }

  const onetToCandidates = new Map() // onet → Map(kldb5d → candidate)
  const matchTypeStats = { exactMatch: 0, closeMatch: 0, narrowMatch: 0, broadMatch: 0, none: 0 }
  for (const [onetCode, entries] of byOnet) {
    // Tier the entries by match quality — only keep the best-available tier.
    // (If an O*NET has exactMatch partners, we should not also pool in broadMatch
    // partners, since those often drift into unrelated occupation families.)
    const bestPriority = Math.max(
      0,
      ...entries.map((e) => MATCH_TYPE_PRIORITY[e.matchType] ?? 0),
    )
    const kept = bestPriority > 0
      ? entries.filter((e) => (MATCH_TYPE_PRIORITY[e.matchType] ?? 0) === bestPriority)
      : entries
    const bucketTier = Object.entries(MATCH_TYPE_PRIORITY).find(([, v]) => v === bestPriority)?.[0] ?? 'none'
    matchTypeStats[bucketTier] = (matchTypeStats[bucketTier] ?? 0) + 1

    // Dedup ISCO codes per O*NET first — multiple ESCO URIs can resolve to the
    // same ISCO-4d; each distinct ISCO path should count as one vote per KldB.
    const iscoSet = new Set()
    for (const { escoUri } of kept) {
      const iscoCode = resolveIscoFromEscoUri(escoUri, escoToIsco)
      if (iscoCode) iscoSet.add(iscoCode)
    }
    for (const iscoCode of iscoSet) {
      const cands = kldbByIsco.get(iscoCode)
      if (!cands) continue
      if (!onetToCandidates.has(onetCode)) onetToCandidates.set(onetCode, new Map())
      const bucket = onetToCandidates.get(onetCode)
      for (const c of cands) {
        const existing = bucket.get(c.kldb5d)
        if (existing) {
          existing.votes = (existing.votes ?? 1) + 1
          if (!existing.schwerpunkt && c.schwerpunkt) existing.schwerpunkt = true
        } else {
          bucket.set(c.kldb5d, { ...c, votes: 1 })
        }
      }
    }
  }

  const mappings = {}
  const stats = { mapped: 0, fallback: 0, byCategory: {}, byAnfDistance: {} }
  for (const [onetCode, meta] of onetMeta) {
    const preferredAnf = meta.jobZone != null ? JOBZONE_TO_ANF[meta.jobZone] : 2
    const bucket = onetToCandidates.get(onetCode)
    const referenceTitle = meta.titleDe ?? meta.titleEn ?? ''
    const pick = bucket ? pickKldb([...bucket.values()], preferredAnf, referenceTitle) : null

    if (pick) {
      const trainingCategory = TRAINING_CATEGORY_BY_ANF[pick.anforderungsniveau]
      mappings[onetCode] = {
        kldbCode: pick.kldb5d,
        kldbName: pick.name,
        anforderungsniveau: pick.anforderungsniveau,
        trainingCategory,
      }
      stats.mapped++
      stats.byCategory[trainingCategory] = (stats.byCategory[trainingCategory] ?? 0) + 1
      const dist = Math.abs(pick.anforderungsniveau - preferredAnf)
      stats.byAnfDistance[dist] = (stats.byAnfDistance[dist] ?? 0) + 1
    } else {
      // Fallback for O*NET codes without KldB match (~2-3%): emit training
      // category from jobZone-derived Anforderungsniveau so filtering still
      // works; leave kldbCode/kldbName null so the UI uses the ONet title.
      const trainingCategory = TRAINING_CATEGORY_BY_ANF[preferredAnf]
      mappings[onetCode] = {
        kldbCode: null,
        kldbName: null,
        anforderungsniveau: preferredAnf,
        trainingCategory,
        fromJobZone: true,
      }
      stats.fallback++
      stats.byCategory[trainingCategory] = (stats.byCategory[trainingCategory] ?? 0) + 1
    }
  }
  return { mappings, stats, matchTypeStats }
}

function main() {
  const { kldbByIsco, source } = loadKldb()
  const escoToIsco = loadEscoToIsco()
  const crosswalk = loadCrosswalk()
  const onetMeta = loadOnetMeta()

  const { mappings, stats, matchTypeStats } = buildMappings(kldbByIsco, escoToIsco, crosswalk, onetMeta)

  console.log(`\n${stats.mapped} / ${onetMeta.size} O*NET codes mapped to KldB, ${stats.fallback} jobZone-fallback only`)
  console.log(`  match tier of mapped codes:`, matchTypeStats)
  console.log(`  by training category:`, stats.byCategory)
  console.log(`  Anf distance from jobZone target (mapped only):`, stats.byAnfDistance)

  const output = {
    meta: {
      source: source.classification,
      publisher: source.publisher,
      systematik_url: source.systematik_url,
      crosswalk_url: source.crosswalk_url,
      license: source.license,
      chain: 'O*NET → ESCO (EU crosswalk) → ISCO-08-4d (tabiya ESCO taxonomy) → KldB-5d (Bundesagentur Umsteigeschlüssel)',
      selectionStrategy: 'Primary ISCO match (Schwerpunkt) with Anforderungsniveau aligned to O*NET jobZone',
      trainingCategories: {
        none: 'Anforderungsniveau 1 — Helfer / ohne geregelte Ausbildung',
        apprenticeship: 'Anforderungsniveau 2 — Fachkraft (2-3 Jahre Berufsausbildung)',
        specialist: 'Anforderungsniveau 3 — Spezialist (Meister, Techniker, Fachwirt, Bachelor)',
        studies: 'Anforderungsniveau 4 — Experte (Master, Diplom, Promotion)',
      },
    },
    mappings,
  }

  writeFileSync(OUTPUT, JSON.stringify(output, null, 2) + '\n', 'utf-8')
  console.log(`\nWrote ${OUTPUT}`)
}

main()
